153→var onUpdateHook = [];
154→var onShownHook = [];
155→
156→var onPageFinished = function () {
157→    if (!resizeDone) {
158→        resizeImages();
159→        /* Re-anchor to answer after image resize since the point changes */
160→        window.location.href = "#answer";
161→    }
162→
163→    var card = document.querySelector(".card");
164→
165→    _runHook(onUpdateHook)
166→        .then(() => {
167→            if (window.MathJax != null) {
168→                /* Anki-Android adds mathjax-needs-to-render" as a class to the card when
169→                   it detects both \( and \) or \[ and \].
170→
171→                   This does not control *loading* MathJax, but rather controls whether or not MathJax
172→                   renders content.  We hide all the content until MathJax renders, because otherwise
173→                   the content loads, and has to reflow after MathJax renders, and it's unsightly.
174→                   However, if we hide all the content every time, folks don't like the repainting after
175→                   every question or answer.  This is a middle-ground, where there is no repainting due to
176→                   MathJax on non-MathJax cards, and on MathJax cards, there is a small flicker, but there's
177→                   no reflowing because the content only shows after MathJax has rendered. */
178→
179→                if (card.classList.contains("mathjax-needs-to-render")) {
180→                    return MathJax.startup.promise
181→                        .then(() => MathJax.typesetPromise([card]))
182→                        .then(() => card.classList.remove("mathjax-needs-to-render"));
183→                }
184→            }
185→        })
186→        .then(() => card.classList.add("mathjax-rendered"))
187→        .then(_runHook(onShownHook));
188→};
